import React, { useState, useEffect } from 'react';
import Header from './components/Header';
import CheckPage from './components/CheckPage';
import LogsPage from './components/LogsPage';
import { pingBackend, BASE_URL } from './api';

export default function App() {
  const [page, setPage] = useState('check');
  const [backendStatus, setBackendStatus] = useState('checking'); // 'checking' | 'online' | 'offline'

  // Ping the backend every 5 seconds
  useEffect(() => {
    async function check() {
      const ok = await pingBackend();
      setBackendStatus(ok ? 'online' : 'offline');
    }
    check();
    const interval = setInterval(check, 5000);
    return () => clearInterval(interval);
  }, []);

  return (
    <div style={{ minHeight: '100vh', display: 'flex', flexDirection: 'column' }}>
      <Header page={page} setPage={setPage} backendStatus={backendStatus} baseUrl={BASE_URL} />
      <main style={{ flex: 1, padding: '2rem 1rem', maxWidth: 900, margin: '0 auto', width: '100%' }}>
        {page === 'check'
          ? <CheckPage backendStatus={backendStatus} />
          : <LogsPage  backendStatus={backendStatus} />}
      </main>
      <footer style={{
        textAlign: 'center', padding: '1.5rem',
        color: 'var(--text-dim)', fontFamily: 'var(--font-mono)',
        fontSize: '0.75rem', borderTop: '1px solid var(--border)'
      }}>
        AI ASSISTANT FIREWALL v1.0 &nbsp;·&nbsp;
        BACKEND: <span style={{ color: backendStatus === 'online' ? 'var(--neon-green)' : backendStatus === 'offline' ? 'var(--neon-red)' : 'var(--text-dim)' }}>
          {backendStatus.toUpperCase()}
        </span>
      </footer>
    </div>
  );
}
